for root, dirs, files in os.walk(base_dir):
    for fname in files:
        if not fname.endswith(".java"):
            continue
        fpath = os.path.join(root, fname)
        with open(fpath, "r") as f:
            content = f.read()

        # Replace ambiguous null constructor with cast version
        content = content.replace(
            "new RMIConnector(null, null)",
            "new RMIConnector((JMXServiceURL)null, (Map)null)"
        )

        # Add throws Exception to main method signature
        content = content.replace(
            "public static void main(String[] args) {",
            "public static void main(String[] args) throws Exception {"
        )

        # Add imports after package statement
        lines = content.split("\n")
        new_lines = []
        import_inserted = False
        for i, line in enumerate(lines):
            new_lines.append(line)
            if line.startswith("package ") and not import_inserted:
                new_lines.append("")
                for imp_line in imports.split("\n"):
                    new_lines.append(imp_line)
                import_inserted = True

        content = "\n".join(new_lines)

        with open(fpath, "w") as f:
            f.write(content)

print("Done!")
